package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.util.List;
import java.util.ArrayList;
import java.lang.reflect.Constructor;
import java.lang.reflect.Field;

class CartTest {

  @Test
  void testGetLineItemsReturnsCorrectList() throws Exception {
    // Create mock LineItem instances using a simple subclass since LineItem class is not found
    class DummyLineItem {}

    Object item1 = new DummyLineItem();
    Object item2 = new DummyLineItem();

    List<Object> items = new ArrayList<>();
    items.add(item1);
    items.add(item2);

    // Use reflection to get Cart class and instantiate Cart with null for lineItems first
    Class<?> cartClass = Class.forName("com.google.gson.examples.android.model.Cart");
    Constructor<?> cartConstructor = cartClass.getConstructor(List.class, String.class, String.class);

    // Instantiate Cart with null lineItems first (will set field manually)
    Object cart = cartConstructor.newInstance(null, "buyerName", "creditCard123");

    // Use reflection to set the private final field lineItems to our dummy list
    Field lineItemsField = cartClass.getDeclaredField("lineItems");
    lineItemsField.setAccessible(true);
    // Cast items to List<LineItem> via raw type, no type safety but works for test
    lineItemsField.set(cart, items);

    // Use reflection to invoke getLineItems method
    @SuppressWarnings("unchecked")
    List<Object> result = (List<Object>) cartClass.getMethod("getLineItems").invoke(cart);

    assertNotNull(result);
    assertEquals(2, result.size());
    assertSame(item1, result.get(0));
    assertSame(item2, result.get(1));
  }
}
